export class RVOAgent {

    pos = { x: 0, z: 0 };
    vel = { x: 0, z: 0 };
    prefVel = { x: 0, z: 0 };

    maxSpeed = 2;
    radius = 0.5;

    locked = false;

    gridX = 0;
    gridZ = 0;

    constructor(x: number, z: number) {
        this.pos.x = x;
        this.pos.z = z;
    }
}

type CircleObstacle = { x: number; z: number; r: number };
type RectObstacle = {
    x: number;
    z: number;
    hx: number;
    hz: number;
    cos: number;
    sin: number;
};

export class RVOSimulator {

    agents: RVOAgent[] = [];

    circleObs: CircleObstacle[] = [];
    rectObs: RectObstacle[] = [];

    grid: Map<string, RVOAgent[]> = new Map();
    cellSize = 1.5;

    timeStep = 1 / 60;

    // ===== battlefield bounds =====
    useBounds = false;
    minX = -99999;
    maxX = 99999;
    minZ = -99999;
    maxZ = 99999;

    setBattlefield(minX: number, maxX: number, minZ: number, maxZ: number) {
        this.useBounds = true;
        this.minX = minX;
        this.maxX = maxX;
        this.minZ = minZ;
        this.maxZ = maxZ;
    }

    addAgent(x: number, z: number) {
        const a = new RVOAgent(x, z);
        this.agents.push(a);
        return a;
    }

    setPrefVelocity(a: RVOAgent, vx: number, vz: number) {
        a.prefVel.x = vx;
        a.prefVel.z = vz;
    }

    addCircleObstacle(x: number, z: number, r: number) {
        this.circleObs.push({ x, z, r });
    }

    addRectObstacle(x: number, z: number, hx: number, hz: number, angle: number) {
        this.rectObs.push({
            x,
            z,
            hx,
            hz,
            cos: Math.cos(angle),
            sin: Math.sin(angle)
        });
    }

    private buildGrid() {

        this.grid.clear();

        for (let a of this.agents) {

            const gx = Math.floor(a.pos.x / this.cellSize);
            const gz = Math.floor(a.pos.z / this.cellSize);

            a.gridX = gx;
            a.gridZ = gz;

            const key = gx + "_" + gz;

            if (!this.grid.has(key)) {
                this.grid.set(key, []);
            }

            this.grid.get(key)!.push(a);
        }
    }

    getNeighbors(a: RVOAgent) {

        const result: RVOAgent[] = [];

        for (let x = -1; x <= 1; x++) {
            for (let z = -1; z <= 1; z++) {

                const key = (a.gridX + x) + "_" + (a.gridZ + z);
                const cell = this.grid.get(key);

                if (!cell) continue;

                for (let other of cell) {
                    if (other !== a) {
                        result.push(other);
                    }
                }
            }
        }

        return result;
    }

    step() {

        this.buildGrid();

        // ===== VELOCITY =====
        for (let a of this.agents) {

            if (a.locked) continue;

            let vx = a.prefVel.x;
            let vz = a.prefVel.z;

            const neighbors = this.getNeighbors(a);

            for (let b of neighbors) {

                const dx = a.pos.x - b.pos.x;
                const dz = a.pos.z - b.pos.z;

                const distSq = dx * dx + dz * dz;
                const minDist = a.radius + b.radius;

                if (distSq < 0.0001) continue;

                if (distSq < minDist * minDist) {

                    const dist = Math.sqrt(distSq);

                    const nx = dx / dist;
                    const nz = dz / dist;

                    const push = (minDist - dist);

                    vx += nx * push * 2;
                    vz += nz * push * 2;

                    const dot = vx * nx + vz * nz;

                    if (dot < 0) {
                        vx -= nx * dot;
                        vz -= nz * dot;
                    }
                }
            }

            // ===== circle obstacle =====
            for (let ob of this.circleObs) {

                const dx = a.pos.x - ob.x;
                const dz = a.pos.z - ob.z;

                const dist = Math.sqrt(dx * dx + dz * dz);
                const minDist = a.radius + ob.r;

                if (dist < minDist && dist > 0.0001) {

                    const nx = dx / dist;
                    const nz = dz / dist;

                    vx += nx * (minDist - dist) * 2;
                    vz += nz * (minDist - dist) * 2;

                    const dot = vx * nx + vz * nz;

                    if (dot < 0) {
                        vx -= nx * dot;
                        vz -= nz * dot;
                    }
                }
            }

            // ===== rect obstacle =====
            for (let ob of this.rectObs) {

                const dx = a.pos.x - ob.x;
                const dz = a.pos.z - ob.z;

                const lx = dx * ob.cos + dz * ob.sin;
                const lz = -dx * ob.sin + dz * ob.cos;

                const px = Math.max(-ob.hx, Math.min(lx, ob.hx));
                const pz = Math.max(-ob.hz, Math.min(lz, ob.hz));

                const ox = lx - px;
                const oz = lz - pz;

                const distSq = ox * ox + oz * oz;

                if (distSq < 1e-6) continue;

                if (distSq < a.radius * a.radius) {

                    const dist = Math.sqrt(distSq);

                    const nxL = ox / dist;
                    const nzL = oz / dist;

                    const nx = nxL * ob.cos - nzL * ob.sin;
                    const nz = nxL * ob.sin + nzL * ob.cos;

                    vx += nx * (a.radius - dist) * 2;
                    vz += nz * (a.radius - dist) * 2;

                    const dot = vx * nx + vz * nz;

                    if (dot < 0) {
                        vx -= nx * dot;
                        vz -= nz * dot;
                    }
                }
            }

            const speed = Math.sqrt(vx * vx + vz * vz);

            if (speed > a.maxSpeed) {
                vx = (vx / speed) * a.maxSpeed;
                vz = (vz / speed) * a.maxSpeed;
            }

            a.vel.x = vx;
            a.vel.z = vz;
        }

        // ===== MOVE =====
        for (let a of this.agents) {

            if (!a.locked) {
                a.pos.x += a.vel.x * this.timeStep;
                a.pos.z += a.vel.z * this.timeStep;
            }

            // ===== battlefield clamp =====
            if (this.useBounds) {
                a.pos.x = Math.max(this.minX + a.radius, Math.min(this.maxX - a.radius, a.pos.x));
                a.pos.z = Math.max(this.minZ + a.radius, Math.min(this.maxZ - a.radius, a.pos.z));
            }
        }

        this.buildGrid();

        // ===== HARD SEPARATION =====
        for (let a of this.agents) {

            const neighbors = this.getNeighbors(a);

            for (let b of neighbors) {

                const dx = b.pos.x - a.pos.x;
                const dz = b.pos.z - a.pos.z;

                const distSq = dx * dx + dz * dz;
                const minDist = a.radius + b.radius;

                if (distSq < 0.0001) continue;

                if (distSq < minDist * minDist) {

                    const dist = Math.sqrt(distSq);
                    const overlap = (minDist - dist) * 0.5;

                    const nx = dx / dist;
                    const nz = dz / dist;

                    if (!a.locked) {
                        a.pos.x -= nx * overlap;
                        a.pos.z -= nz * overlap;
                    }

                    if (!b.locked) {
                        b.pos.x += nx * overlap;
                        b.pos.z += nz * overlap;
                    }
                }
            }
        }

        // clamp again after separation
        if (this.useBounds) {
            for (let a of this.agents) {
                a.pos.x = Math.max(this.minX + a.radius, Math.min(this.maxX - a.radius, a.pos.x));
                a.pos.z = Math.max(this.minZ + a.radius, Math.min(this.maxZ - a.radius, a.pos.z));
            }
        }
    }
}